$ErrorActionPreference="Stop";$project=(Get-Location).Path;$marker=Join-Path $project ".connectiq-v0.8.0-last-backup.txt";if(!(Test-Path $marker)){throw "No v0.8.0 backup marker found."};$backup=(Get-Content $marker -Raw).Trim();Get-ChildItem $backup -Recurse -File | ForEach-Object {$rel=$_.FullName.Substring($backup.Length).TrimStart('\');$dest=Join-Path $project $rel;New-Item -ItemType Directory -Force -Path (Split-Path $dest)|Out-Null;Copy-Item $_.FullName $dest -Force};Write-Host "Rollback complete from $backup" -ForegroundColor Yellow
